def count_substrings_with_same_ends(s):
    count = 0
    n = len(s)
    for i in range(n):
        for j in range(i, n):
            if s[i] == s[j]:
                count += 1
    return count

# Test cases
assert count_substrings_with_same_ends('aba') == 4
assert count_substrings_with_same_ends('abcab') == 7
assert count_substrings_with_same_ends('abc') == 3

